-- Step 1: Create Table
DROP TABLE IF EXISTS AMAZONSALE;

CREATE TABLE AMAZONSALE (
  order_id TEXT,
  date TEXT,
  status TEXT,
  fulfilment TEXT,
  sales_channel TEXT,
  style TEXT,
  category TEXT,
  size TEXT,
  asin TEXT,
  courier_status TEXT,
  qty INTEGER,
  currency TEXT,
  amount REAL,
  ship_city TEXT,
  ship_state TEXT,
  ship_country TEXT,
  b2b TEXT,
  fulfilled_by TEXT
);

